class Solution:
    def binaryTreePaths(self, root):
        res = []
        def dfs(node, acc):
            acc = acc + [str(node.val)]
            if node.left is None and node.right is None:
                res.append('->'.join(acc))
                return
            if node.left is not None:
                dfs(node.left, acc)
            if node.right is not None:
                dfs(node.right, acc)
        if root is not None:
            dfs(root, [])
        return res

