var binaryTreePaths = function(root) {
    const res = [];
    const dfs = (node, acc) => {
        acc = acc.concat([String(node.val)]);
        if (node.left === null && node.right === null) {
            res.push(acc.join('->'));
            return;
        }
        if (node.left !== null) dfs(node.left, acc);
        if (node.right !== null) dfs(node.right, acc);
    };
    if (root !== null) dfs(root, []);
    return res;
};
